mapper.select:
SELECT u.user_id AS userId, u.role_id AS roleId, r.role_name AS roleName, u.NAME AS userName, u.email, phone, address, u.created_at AS createdAt, u.birth FROM (SELECT * FROM user
role_id = #{roleType}
AND NAME LIKE CONCAT('%', #{searchWord}, '%')
) u INNER JOIN role r ON u.role_id = r.role_id ORDER BY u.role_Id LIMIT #{beginRow}, #{rowPerPage}

SELECT va.assignment_id AS assignmentId, p.payment_id AS paymentId, lt.day_of_week AS dayOfWeek, DATE_SUB(lt.end_time, INTERVAL 10 MINUTE) AS endTime FROM payment p INNER JOIN student_enrollment se ON p.enrollment_id = se.enrollment_id INNER JOIN lecture lt ON se.lecture_id = lt.lecture_id INNER JOIN vehicle_assignment va ON va.lecture_id = lt.lecture_id LEFT JOIN vehicle_cancel vc ON vc.assignment_id = va.assignment_id AND DATE(vc.decided_at) = CURDATE() WHERE lt.end_date >= CURDATE() AND vc.assignment_id IS NULL
AND lt.day_of_week = #{dayOfWeek}
AND DATE_FORMAT(DATE_SUB(lt.end_time, INTERVAL 10 MINUTE), '%H:%i') = #{targetTime}

SELECT u.name AS studentName, sb.name AS subjectName, lt.day_of_week AS dayOfWeek, vc.cancel_reason AS cancelReason, vc.decided_at AS decidedAt FROM vehicle_cancel vc INNER JOIN payment p ON vc.payment_id = p.payment_id INNER JOIN student_enrollment se ON p.enrollment_id = se.enrollment_id INNER JOIN lecture lt ON se.lecture_id = lt.lecture_id INNER JOIN subject sb ON lt.subject_id = sb.subject_id INNER JOIN user u ON se.student_id = u.user_id
AND u.name LIKE CONCAT('%', #{searchWord}, '%')
AND DATE(vc.decided_at) = #{searchType}
ORDER BY decidedAt DESC LIMIT #{beginRow}, #{rowPerPage}

SELECT COUNT(*) FROM vehicle_cancel vc INNER JOIN payment p ON vc.payment_id = p.payment_id INNER JOIN student_enrollment se ON p.enrollment_id = se.enrollment_id INNER JOIN lecture lt ON se.lecture_id = lt.lecture_id INNER JOIN subject sb ON lt.subject_id = sb.subject_id INNER JOIN user u ON se.student_id = u.user_id
AND u.name LIKE CONCAT('%', #{searchWord}, '%')
AND DATE(vc.decided_at) = #{searchType}

SELECT st.user_id AS studentId, st.name AS studentName, vc.vehicle_no AS vehicleNo, dr.user_id AS driverId, dr.name AS driverName, sb.name AS subjectName, lt.day_of_week AS dayOfWeek, lt.end_time AS endTime FROM payment p INNER JOIN student_enrollment se ON p.enrollment_id = se.enrollment_id INNER JOIN ( SELECT * FROM lecture
end_date >= CURDATE()
AND lecture_id = #{lectureId}
) lt ON se.lecture_id = lt.lecture_id INNER JOIN vehicle_assignment va ON va.lecture_id = lt.lecture_id INNER JOIN vehicle vc ON va.vehicle_id = vc.vehicle_id INNER JOIN user dr ON va.driver_id = dr.user_id INNER JOIN subject sb ON sb.subject_id = lt.subject_id INNER JOIN ( SELECT * FROM user
AND name LIKE CONCAT('%', #{searchName}, '%')
) st ON se.student_id = st.user_id

SELECT COUNT(*) FROM user
role_id = #{roleType}
AND NAME LIKE CONCAT('%', #{searchWord}, '%')

SELECT COUNT(*) FROM notice
target_role_id = #{roleType}
AND title LIKE CONCAT('%', #{searchWord}, '%')

SELECT qna_id AS qnaId, parent_id AS parentId, admin_id AS adminId, question, answer, created_at AS createdAt, answered_at AS answeredAt FROM qna
AND question LIKE CONCAT('%', #{searchWord}, '%')
ORDER BY answered_at IS NOT NULL, CASE WHEN answered_at IS NULL THEN created_at ELSE NULL END ASC, CASE WHEN answered_at IS NOT NULL THEN created_at ELSE NULL END DESC LIMIT #{beginRow}, #{rowPerPage}

