UPDATE subject SET
name = #{subjectName}, description = #{description}
WHERE subject_id = #{subjectId};

mapper.select:
SELECT se.enrollment_id AS enrollmentId, se.student_id AS studentId, u.name AS studentName, sb.name AS subjectName, DATE_FORMAT(se.enrolled_at, '%Y-%m-%d %H:%i') AS enrolledAt, CASE se.status WHEN 'PENDING' THEN '납부 대기' WHEN 'PAID' THEN '납부 완료' WHEN 'CANCEL' THEN '신청 취소' WHEN 'REFUNDWAIT' THEN '환불 대기' WHEN 'REFUND' THEN '환불 완료' END AS status FROM student_enrollment se INNER JOIN (SELECT * FROM lecture WHERE end_date >= CURDATE()) lt ON se.lecture_id = lt.lecture_id INNER JOIN subject sb ON sb.subject_id = lt.subject_id INNER JOIN user u ON se.student_id = u.user_id
sb.name = #{searchType}
AND u.name LIKE CONCAT('%', #{searchWord}, '%')
ORDER BY enrolledAt DESC, enrollmentId DESC LIMIT #{beginRow}, #{rowPerPage}

SELECT count(*) FROM student_enrollment se INNER JOIN (SELECT * FROM lecture WHERE end_date >= CURDATE()) lt ON se.lecture_id = lt.lecture_id INNER JOIN subject sb ON sb.subject_id = lt.subject_id INNER JOIN user u ON se.student_id = u.user_id
sb.name = #{searchType}
AND u.name LIKE CONCAT('%', #{searchWord}, '%')

SELECT p.payment_id AS paymentId, sb.name AS subjectName, st.name AS studentName, p.amount, DATE_FORMAT(p.paid_at, '%Y-%m-%d %H:%i') AS paidAt FROM payment p INNER JOIN student_enrollment se ON p.enrollment_id = se.enrollment_id INNER JOIN lecture lt ON se.lecture_id = lt.lecture_id INNER JOIN subject sb ON lt.subject_id = sb.subject_id INNER JOIN user st ON se.student_id = st.user_id
sb.name = #{searchType}
AND st.name LIKE CONCAT('%', #{searchWord}, '%')
ORDER BY paidAt DESC, paymentId DESC LIMIT #{beginRow}, #{rowPerPage}

SELECT COUNT(*) FROM payment p INNER JOIN student_enrollment se ON p.enrollment_id = se.enrollment_id INNER JOIN lecture lt ON se.lecture_id = lt.lecture_id INNER JOIN subject sb ON lt.subject_id = sb.subject_id INNER JOIN user st ON se.student_id = st.user_id
sb.name = #{searchType}
AND st.name LIKE CONCAT('%', #{searchWord}, '%')

SELECT se.enrollment_id AS enrollmentId, sb.name AS subjectName, st.name AS studentName, st.phone, se.enrolled_at AS enrolledAt FROM (SELECT * FROM student_enrollment WHERE STATUS = 'CANCEL') se INNER JOIN lecture lt ON se.lecture_id = lt.lecture_id INNER JOIN subject sb ON lt.subject_id = sb.subject_id INNER JOIN user st ON se.student_id = st.user_id
sb.name = #{searchType}
AND st.name LIKE CONCAT('%', #{searchWord}, '%')
ORDER BY enrolledAt DESC, enrollmentId DESC LIMIT #{beginRow}, #{rowPerPage}

SELECT COUNT(*) FROM (SELECT * FROM student_enrollment WHERE status = 'CANCEL') se INNER JOIN lecture lt ON se.lecture_id = lt.lecture_id INNER JOIN subject sb ON lt.subject_id = sb.subject_id INNER JOIN user st ON se.student_id = st.user_id
sb.name = #{searchType}
AND st.name LIKE CONCAT('%', #{searchWord}, '%')

SELECT se.enrollment_id AS enrollmentId, u.name AS studentName, sb.name AS subjectName, CASE se.status WHEN 'REFUNDWAIT' THEN '환불 대기' WHEN 'REFUND' THEN '환불 완료' END AS status, se.enrolled_at AS enrolledAt FROM (SELECT * FROM student_enrollment WHERE status IN ('REFUNDWAIT', 'REFUND')) se INNER JOIN lecture lt ON se.lecture_id = lt.lecture_id INNER JOIN subject sb ON lt.subject_id = sb.subject_id INNER JOIN user u ON se.student_id = u.user_id
sb.name = #{searchType}
AND u.name LIKE CONCAT('%', #{searchWord}, '%')
ORDER BY enrolledAt DESC, enrollmentId DESC LIMIT #{beginRow}, #{rowPerPage}

SELECT COUNT(*) FROM (SELECT * FROM student_enrollment WHERE status IN ('REFUNDWAIT', 'REFUND')) se INNER JOIN lecture lt ON se.lecture_id = lt.lecture_id INNER JOIN subject sb ON lt.subject_id = sb.subject_id INNER JOIN user u ON se.student_id = u.user_id
sb.name = #{searchType}
AND u.name LIKE CONCAT('%', #{searchWord}, '%')

SELECT lt.lecture_id AS lectureId, sb.name AS subjectName, u.name AS teacherName, cr.name AS classroomName, cr.location AS location, DATE_FORMAT(lt.start_time, '%H:%i') AS startTime, DATE_FORMAT(lt.end_time, '%H:%i') AS endTime, lt.day_of_week AS 'dayOfWeek', lt.start_date AS startDate, lt.end_date AS endDate, va.assignment_id AS assignmentId, v.vehicle_no AS vehicleNo, d.name AS driverName, va.location AS vehicleLocation FROM lecture lt INNER JOIN subject sb ON lt.subject_id = sb.subject_id INNER JOIN classroom cr ON lt.classroom_id = cr.classroom_id INNER JOIN teacher_assignment ta ON lt.lecture_id = ta.lecture_id INNER JOIN user u ON ta.teacher_id = u.user_id LEFT JOIN vehicle_assignment va ON lt.lecture_id = va.lecture_id LEFT JOIN vehicle v ON va.vehicle_id = v.vehicle_id LEFT JOIN user d ON va.driver_id = d.user_id
sb.name = #{searchType}
AND u.name LIKE CONCAT('%', #{searchWord}, '%')
ORDER BY startDate DESC, startTime DESC LIMIT #{beginRow}, #{rowPerPage}

SELECT COUNT(*) FROM lecture lt INNER JOIN subject sb ON lt.subject_id = sb.subject_id INNER JOIN classroom cr ON lt.classroom_id = cr.classroom_id INNER JOIN teacher_assignment ta ON lt.lecture_id = ta.lecture_id INNER JOIN user u ON ta.teacher_id = u.user_id
sb.name = #{searchType}
AND u.name LIKE CONCAT('%', #{searchWord}, '%')

SELECT n.notice_id AS noticeId, n.title, n.content, r.role_name AS roleName, DATE_FORMAT(n.created_at, '%Y-%m-%d') AS createdAt FROM notice n INNER JOIN role r ON r.role_id = n.target_role_id
n.target_role_id = #{roleType}
AND n.title LIKE CONCAT('%', #{searchWord}, '%')
ORDER BY n.created_at DESC LIMIT #{beginRow}, #{rowPerPage}

